const h3Fetch = (async (input, _init) => {
    let url: string
    let init = _init
    if (typeof input === 'string') {
      url = input
    }
    else if (input instanceof URL) {
      url = input.toString()
    }
    else {
      url = input.url
      init = {
        method: init?.method ?? input.method,
        body: init?.body ?? input.body,
        headers: init?.headers ?? input.headers,
      }
    }

    const base = url.split('?')[0]!
    if (registry.has(base) || registry.has(url)) {
      return h3App.fetch(new Request('/_' + url, init))
    }
    if (url.startsWith('/')) {
      return new Response('Not Found', { status: 404, statusText: 'Not Found' })
    }
    return _fetch(input, _init)
  }) as typeof fetch

const SlpComponent = defineComponent({
  name: 'SwitchLocalePathLink',
  props: {
    locale: {
      type: String as PropType<Locale>,
      required: true,
    },
  },
  setup(props, { slots, attrs }) {
    const nuxtApp = useNuxtApp()
    const payload = useComposableContext(nuxtApp).localePathPayload
    const switchLocalePath = useSwitchLocalePath(nuxtApp)

    const resolved = computed(() => {
      if (__I18N_STRICT_SEO__ && nuxtApp.isHydrating && Object.keys(payload ?? {}).length && !payload?.[props.locale]) {
        return '#'
      }
      return encodeURI(switchLocalePath(props.locale)) || (__I18N_STRICT_SEO__ && '#') || ''
    })

    const disabled = computed(() => (__I18N_STRICT_SEO__ && resolved.value === '#') || undefined)

    return () => h(NuxtLink, { ...attrs, 'to': resolved.value, 'data-i18n-disabled': disabled.value }, slots.default)
  },
})

if (import.meta.server) {
  for (const locale of localeCodes) {
    try {
      const messages = await $fetch(`${__I18N_SERVER_ROUTE__}/${__I18N_LOCALE_HASHES__[locale]}/${locale}/messages.json`)
      for (const locale of Object.keys(messages)) {
        nuxt.$i18n.mergeLocaleMessage(locale, messages[locale])
      }
    } catch (e) {
      console.warn('Error loading messages', e)
    }
  }

  ctx.preloaded = true

  const serverI18n = nuxt.ssrContext?.event.context.nuxtI18n
  // set server context messages
  if (serverI18n) {
    const msg = unref(ctx.vueI18n.global.messages) as LocaleMessages<DefineLocaleMessage>
    serverI18n.messages ??= {}
    for (const k in msg) {
      serverI18n.messages[k] = msg[k]!
    }
  }
}

return {
  ...config,
  key: __I18N_STRICT_SEO__ ? 'key' : 'id',
  locales,
  baseUrl,
  canonicalQueries,
  hreflangLinks: ctx.routingOptions.hreflangLinks,
  defaultLocale: ctx.routingOptions.defaultLocale,
  strictCanonicals: __I18N_STRICT_SEO__ || ctx.routingOptions.strictCanonicals,
  getRouteBaseName: ctx.getRouteBaseName,
  getCurrentRoute: () => ctx.router.currentRoute.value,
  getCurrentLanguage: () => currentLocale.language,
  getCurrentDirection: () => currentLocale.dir || __DEFAULT_DIRECTION__,
  getLocaleRoute: route => localeRoute(ctx, route),
  getLocalizedRoute: (locale, route) => switchLocalePath(ctx, locale, route),
  getRouteWithoutQuery: () => {
    try {
      return assign({}, ctx.router.resolve({ query: {} }), { meta: ctx.router.currentRoute.value.meta })
    } catch {
      return undefined
    }
  },
}

for (let i = 0; i < configs.length; i++) {
  statements.push(
    [
      `  import.meta.hot.accept("${configs[i]!.relative}", async mod => {`,
      //   load configs before replacing loader
      `    const [oldData, newData] = await Promise.all([loadCfg(vueI18nConfigs[${i}]), loadCfg(() => Promise.resolve(mod))]);`,
      //   replace config loader
      `    vueI18nConfigs[${i}] = () => Promise.resolve(mod)`,
      //   compare data - reload configs if _only_ replaceable properties have changed
      `    if(useNuxtApp()._nuxtI18n.dev.deepEqual(oldData, newData, ['messages', 'numberFormats', 'datetimeFormats'])) {`,
      `      return await useNuxtApp()._nuxtI18n.dev.resetI18nProperties()`,
      `    }`,
      //   communicate to vite plugin to trigger a page load
      `    import.meta.hot.send('i18n:options-complex-invalidation', {})`,
      `  })`,
    ].join('\n'),
  )
}
